import React, { useState, useRef, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';

const RoyAI = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [messages, setMessages] = useState([
    {
      text: "Hi! I'm RoyAI, a digital version of Roy. Ask me anything about Roy's skills, experience, or interests!",
      sender: 'ai'
    }
  ]);
  const [input, setInput] = useState('');
  const messagesEndRef = useRef(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!input.trim()) return;

    // Add user message
    const userMessage = { text: input, sender: 'user' };
    setMessages(prev => [...prev, userMessage]);
    setInput('');

    // Simulate AI thinking
    const thinkingMessage = { text: "Thinking...", sender: 'ai', isThinking: true };
    setMessages(prev => [...prev, thinkingMessage]);

    // Simulate AI response (replace this with actual AI integration later)
    setTimeout(() => {
      setMessages(prev => prev.filter(msg => !msg.isThinking));
      const aiResponse = generateResponse(input);
      setMessages(prev => [...prev, { text: aiResponse, sender: 'ai' }]);
    }, 1000);
  };

  const generateResponse = (input) => {
    // This is a simple response system - you can replace this with a more sophisticated AI later
    const lowerInput = input.toLowerCase();

    if (lowerInput.includes('skill') || lowerInput.includes('language')) {
      return "I'm proficient in Python, JavaScript, Java, C++, C, SQL, x86-64 Assembly, and HTML/CSS. I also work with React, Node.js, Express.js, Flask, and PostgreSQL.";
    }

    if (lowerInput.includes('experience') || lowerInput.includes('work')) {
      return "I'm currently focused on Software Engineering with a specialization in Artificial Intelligence. I'm building my portfolio and looking for opportunities to apply my skills.";
    }

    if (lowerInput.includes('interest') || lowerInput.includes('hobby')) {
      return "I'm passionate about AI and software development. I enjoy working on projects that combine these interests and am always eager to learn new technologies.";
    }

    if (lowerInput.includes('contact') || lowerInput.includes('reach')) {
      return "You can reach out to me through my portfolio or professional networks. I'm always interested in connecting with fellow developers and AI enthusiasts.";
    }

    return "I'm RoyAI, a digital representation of Roy. I can tell you about Roy's skills, experience, and interests. What would you like to know?";
  };

  return (
    <>
      <motion.button
        className="roy-ai-button"
        onClick={() => setIsOpen(!isOpen)}
        whileHover={{ scale: 1.05 }}
        whileTap={{ scale: 0.95 }}
      >
        {isOpen ? 'Close RoyAI' : 'Chat with RoyAI'}
      </motion.button>

      <AnimatePresence>
        {isOpen && (
          <motion.div
            className="chat-window"
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0, y: 20 }}
            transition={{ duration: 0.3 }}
          >
            <div className="chat-messages">
              {messages.map((message, index) => (
                <motion.div
                  key={index}
                  className={`message ${message.sender}`}
                  initial={{ opacity: 0, y: 10 }}
                  animate={{ opacity: 1, y: 0 }}
                  transition={{ duration: 0.3 }}
                >
                  {message.text}
                </motion.div>
              ))}
              <div ref={messagesEndRef} />
            </div>
            <form onSubmit={handleSubmit} className="chat-input-form">
              <input
                type="text"
                value={input}
                onChange={(e) => setInput(e.target.value)}
                placeholder="Ask me anything..."
                className="chat-input"
              />
              <button type="submit" className="send-button">
                Send
              </button>
            </form>
          </motion.div>
        )}
      </AnimatePresence>
    </>
  );
};

export default RoyAI;
